import java.io.BufferedReader;
import java.io.File;
import java.io.FileReader;
import java.io.IOException;

public class SecurePathTraversalExample {
    public static void main(String[] args) {
        String userInput = "../somefile.txt"; // User input containing path traversal characters

        String baseDirectory = "/path/to/directory/";
        String filePath = new File(baseDirectory, userInput).getCanonicalPath(); // Use canonical path to resolve and sanitize the input

        if (!filePath.startsWith(baseDirectory)) {
            System.err.println("Invalid file path specified.");
            return;
        }

        try (BufferedReader reader = new BufferedReader(new FileReader(filePath))) {
            String line;
            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }
        } catch (IOException e) {
            System.err.println("Error reading file: " + e.getMessage());
        }
    }
}

